{"command":"$env:DATABASE_URL='postgresql://postgres.eqccjfbyrywsqkxxpjvg:ECUCkNBgLLbdamXtAu5uL2QcMhjswfSiJsAxdW9hgaEI26KL9!@aws-1-us-east-1.pooler.supabase.com:5432/postgres'; @'
const fs = require('fs');
const postgres = require('postgres');
const outPath = 'C:/repos/oracle/scratchpad-corpus-composition.json';
const categorySql = `
  case
    when lower(coalesce(d.file_type,'')) like 'image/%' or lower(d.file_name) ~ '\\.(png|jpe?g|webp|gif|tiff?|bmp|heic)$' then 'image'
    when lower(coalesce(d.file_type,'')) like '%pdf%' or lower(d.file_name) ~ '\\.pdf$' then 'pdf'
    when lower(coalesce(d.file_type,'')) like '%spreadsheet%' or lower(coalesce(d.file_type,'')) like '%excel%' or lower(coalesce(d.file_type,'')) like '%sheet%' or lower(d.file_name) ~ '\\.(xlsx|xls)$' then 'xlsx'
    when lower(coalesce(d.file_type,'')) like '%wordprocessingml%' or lower(coalesce(d.file_type,'')) like '%msword%' or lower(d.file_name) ~ '\\.(docx|doc)$' then 'docx'
    when lower(coalesce(d.file_type,'')) like 'text/%' or lower(coalesce(d.file_type,'')) in ('text','txt','md','markdown','csv','application/json') or lower(d.file_name) ~ '\\.(txt|md|markdown|csv|json)$' then 'text'
    else 'other'
  end`;
function inc(obj, key, n = 1) { obj[key ?? 'NULL'] = (obj[key ?? 'NULL'] || 0) + n; }
function pct(n, d) { return d ? Math.round((n * 10000) / d) / 100 : 0; }
function median(nums) { const a = [...nums].sort((x,y)=>x-y); if (!a.length) return 0; const m = Math.floor(a.length/2); return a.length % 2 ? a[m] : (a[m-1]+a[m])/2; }
function avg(nums) { return nums.length ? Math.round((nums.reduce((a,b)=>a+b,0)/nums.length)*100)/100 : 0; }
(async () => {
  const sql = postgres(process.env.DATABASE_URL, { max: 3, ssl: 'require' });
  const [target, docs, maps, claimDocs, distinctFileTypes] = await Promise.all([
    sql`select current_database() as database, current_user as user, inet_server_addr()::text as server_addr`,
    sql.unsafe(`
      select d.id::text, d.file_name, d.file_type, ${categorySql} as category, d.status::text as status,
             d.macro_health::text as macro_health, coalesce(count(dc.id),0)::int as chunk_count
      from documents d
      left join document_chunks dc on dc.document_id = d.id
      group by d.id, d.file_name, d.file_type, category, d.status, d.macro_health
      order by d.created_at desc`),
    sql.unsafe(`
      select swm.id::text as map_id, swm.document_id::text, d.file_type, ${categorySql} as category,
             d.macro_health::text as macro_health, swm.map_kind, swm.status,
             case when jsonb_typeof(swm.nodes_json) = 'array' then jsonb_array_length(swm.nodes_json) else 0 end::int as node_count,
             case when jsonb_typeof(swm.edges_json) = 'array' then jsonb_array_length(swm.edges_json) else 0 end::int as edge_count
      from source_workflow_maps swm
      join documents d on d.id = swm.document_id
      where swm.document_id is not null and swm.superseded_by_map_id is null`),
    sql.unsafe(`
      select distinct c.id::text as claim_id, c.map_element_ref, d.id::text as document_id, ${categorySql} as category
      from claims c
      join claim_evidence ce on ce.claim_id = c.id
      join document_chunks dc on dc.id = ce.source_document_chunk_id
      join documents d on d.id = dc.document_id`),
    sql`select file_type, count(*)::int as documents from documents group by file_type order by documents desc, file_type`
  ]);

  const documentsByType = new Map();
  const contentByCategory = new Map();
  const docById = new Map(docs.map(d => [d.id, {...d, promoted_claim_count: 0, active_map_kind: 'none', active_map_count: 0, active_map_node_count: 0, active_map_edge_count: 0}]));
  for (const d of docs) {
    const typeKey = `${d.file_type ?? 'NULL'}|${d.category}`;
    if (!documentsByType.has(typeKey)) documentsByType.set(typeKey, { file_type: d.file_type, category: d.category, document_count: 0, status_distribution: {}, macro_health_distribution: {} });
    const t = documentsByType.get(typeKey); t.document_count++; inc(t.status_distribution, d.status); inc(t.macro_health_distribution, d.macro_health);
    if (!contentByCategory.has(d.category)) contentByCategory.set(d.category, []);
    contentByCategory.get(d.category).push(d.chunk_count);
  }
  const ingestedContentShape = [...contentByCategory.entries()].sort().map(([category, counts]) => ({
    category, documents: counts.length, documents_with_chunks: counts.filter(c => c > 0).length,
    avg_chunks_per_document: avg(counts), median_chunks_per_document: median(counts), min_chunks: Math.min(...counts), max_chunks: Math.max(...counts)
  }));

  const workflowByCategory = new Map();
  for (const m of maps) {
    if (!workflowByCategory.has(m.category)) workflowByCategory.set(m.category, { category: m.category, documents: new Set(), active_maps: 0, workflow_maps: 0, reference_maps: 0, other_map_kind_maps: 0, non_empty_graph_maps: 0, empty_graph_maps: 0, map_status_distribution: {}, document_macro_health_distribution: {} });
    const w = workflowByCategory.get(m.category);
    w.documents.add(m.document_id); w.active_maps++;
    if (m.map_kind === 'workflow') w.workflow_maps++; else if (m.map_kind === 'reference') w.reference_maps++; else w.other_map_kind_maps++;
    if ((m.node_count || 0) + (m.edge_count || 0) > 0) w.non_empty_graph_maps++; else w.empty_graph_maps++;
    inc(w.map_status_distribution, m.status);
    const dd = docById.get(m.document_id);
    if (dd) {
      const kinds = dd.active_map_kind === 'none' ? new Set() : new Set(dd.active_map_kind.split(', '));
      kinds.add(m.map_kind ?? 'NULL'); dd.active_map_kind = [...kinds].sort().join(', ');
      dd.active_map_count++; dd.active_map_node_count += m.node_count || 0; dd.active_map_edge_count += m.edge_count || 0;
    }
  }
  for (const w of workflowByCategory.values()) {
    const seenDocHealth = new Map();
    for (const docId of w.documents) { const d = docById.get(docId); if (d) inc(seenDocHealth, d.macro_health); }
    w.document_macro_health_distribution = seenDocHealth;
  }
  const workflowOutcomes = [...workflowByCategory.values()].sort((a,b)=>a.category.localeCompare(b.category)).map(w => ({
    category: w.category, documents_with_active_map: w.documents.size, active_maps: w.active_maps, workflow_maps: w.workflow_maps,
    reference_maps: w.reference_maps, other_map_kind_maps: w.other_map_kind_maps, non_empty_graph_maps: w.non_empty_graph_maps,
    empty_graph_maps: w.empty_graph_maps, map_status_distribution: w.map_status_distribution, document_macro_health_distribution: Object.fromEntries(w.document_macro_health_distribution)
  }));

  const claimByCategory = new Map();
